const CLOUDINARY_BASE = "https://res.cloudinary.com/lnkoms9m/image/upload";

// Keep the chooser limited to the assets that have completed the Cloudinary import.
export const AVATAR_DECORATIONS = ALL_AVATAR_DECORATIONS.filter(({ id }) => Number(id) <= 10);

const CLOUDINARY_LIST_URL = "https://res.cloudinary.com/lnkoms9m/image/list/dislight-avatar-decoration.json";

type CloudinaryListResponse = {
  resources?: Array<{ public_id?: string; display_name?: string }>;
};

export async function fetchLiveAvatarDecorations() {
  const response = await fetch(CLOUDINARY_LIST_URL, { cache: "no-store" });
  if (!response.ok) throw new Error("Cloudinary decoration list is unavailable.");
  const data = await response.json() as CloudinaryListResponse;
  return (data.resources ?? [])
    .map(({ public_id, display_name }) => {
      const id = public_id?.split("/").at(-1);
      return id && /^\d{3}$/.test(id) ? { id, label: display_name || `Decoration ${id}`, sourceUrl: "" } : null;
    })
    .filter((item): item is AvatarDecoration => item !== null)
    .sort((a, b) => a.id.localeCompare(b.id));
}

// Existing profiles retain their old decoration until the owner chooses a new catalogue item.
const LEGACY_DECORATIONS = new Set([
  "bubble", "chun-li", "dreamy", "heart", "helly-kitty", "leafs", "lights", "milk", "moon", "rainbow",
  "rawr", "sparkly", "sparkly-pink", "spider-man", "toy-story", "venom", "arcane-anomaly", "arcane-boom",
  "arcane-jynx", "arcane-powder",
]);

export function decorationUrl(id: string | null | undefined, animated: boolean) {
  if (!id) return null;
  if (LEGACY_DECORATIONS.has(id)) return `/decorations/${id}${animated ? "" : "-still"}.png`;
  const item = ALL_AVATAR_DECORATIONS.find((decoration) => decoration.id === id);
  if (!item) return null;
  if (!/^\d{3}$/.test(id)) return null;
  // Preserve Cloudinary's uploaded APNG verbatim in active contexts. Applying
  // an on-the-fly transformation here can flatten multi-frame PNG delivery.
  if (animated) return `${CLOUDINARY_BASE}/dislight/avatar-decorations/${id}.png`;
  return `${CLOUDINARY_BASE}/c_limit,w_96/pg_1/f_png/dislight/avatar-decorations/${id}.png`;
}